#!/usr/bin/env python3
"""Hand-carried MCP stdio transport for the freshly built vvx binary.

Usage: jjx_stdio.py <command> <params-json> [officium]
Prints the jjx tool result text to stdout.
"""
import json, subprocess, sys

VVX = "/Users/bhyslop/projects/rbm_alpha_recipemuster/Tools/vvk/bin/vvx"
MODEL = "claude-fable-5[1m]"

def main():
    command = sys.argv[1]
    params = json.loads(sys.argv[2]) if len(sys.argv) > 2 and sys.argv[2] else {}
    officium = sys.argv[3] if len(sys.argv) > 3 else None

    args = {"command": command, "params": params, "model": MODEL}
    if officium:
        args["officium"] = officium

    msgs = [
        {"jsonrpc": "2.0", "id": 1, "method": "initialize", "params": {
            "protocolVersion": "2024-11-05",
            "capabilities": {},
            "clientInfo": {"name": "jjx-stdio-shim", "version": "0.1"}}},
        {"jsonrpc": "2.0", "method": "notifications/initialized"},
        {"jsonrpc": "2.0", "id": 2, "method": "tools/call", "params": {
            "name": "jjx", "arguments": args}},
    ]
    payload = "".join(json.dumps(m) + "\n" for m in msgs)
    proc = subprocess.run(
        [VVX, "mcp"], input=payload.encode(), capture_output=True, timeout=120,
        cwd="/Users/bhyslop/projects/rbm_alpha_recipemuster")
    for line in proc.stdout.decode().splitlines():
        try:
            obj = json.loads(line)
        except json.JSONDecodeError:
            continue
        if obj.get("id") == 2:
            result = obj.get("result")
            if result is None:
                print(json.dumps(obj.get("error"), indent=2))
                sys.exit(1)
            for item in result.get("content", []):
                if item.get("type") == "text":
                    print(item["text"])
            if result.get("isError"):
                sys.exit(1)
            return
    sys.stderr.write(proc.stderr.decode())
    sys.exit(1)

if __name__ == "__main__":
    main()

